import React from 'react';
import {
  Tabs,
  Tab,
  Container,
  Box,
  Typography,
  Grid,
  Button,
  CircularProgress,
  Alert
} from '@mui/material';
import { useBookings } from '../context/BookingContext';

const Bookings = () => {
  const { 
    bookings, 
    loading, 
    getActiveBookings, 
    getPastBookings, 
    getIncomingBookings 
  } = useBookings();
  const [activeTab, setActiveTab] = React.useState(0);
  const handleChangeTab = (event, newValue) => {
    setActiveTab(newValue);
  };
  const [alert, setAlert] = React.useState({ open: false, message: '', severity: 'info' });

  const showAlert = (message, severity = 'info') => {
    setAlert({ open: true, message, severity });
    setTimeout(() => {
      setAlert({ ...alert, open: false });
    }, 3000);
  };

  const renderBookingCard = (booking) => (
    <Grid item xs={12} sm={8} md={6} key={booking.id}>
      <Box sx={{
        p: 3,
        mb: 2,
        backgroundColor: '#ffffff',
        borderRadius: '16px',
        boxShadow: '0 4px 12px rgba(0, 128, 128, 0.1)',
        transition: 'transform 0.3s ease-in-out, box-shadow 0.3s ease-in-out',
        '&:hover': {
          transform: 'translateY(-5px)',
          boxShadow: '0 8px 20px rgba(0, 128, 128, 0.15)',
        },
        display: 'flex',
        flexDirection: 'column',
        gap: 1.5,
      }}>
        <Typography 
          variant="caption" 
          sx={{
            alignSelf: 'flex-start',
            px: 1.5,
            py: 0.5,
            borderRadius: '20px',
            fontWeight: 600,
            color: 'white',
            backgroundColor: booking.status === 'active' ? '#4CAF50' : 
                             booking.status === 'past' ? '#757575' : 
                             booking.status === 'incoming' ? '#FFC107' : '#008080',
          }}
        >
          {booking.status}
        </Typography>
        <Typography variant="h6" sx={{ fontWeight: 700, color: '#008080' }}>{booking.listing_title}</Typography>
        <Typography variant="body2" color="text.secondary">Owner: <span style={{ fontWeight: 600, color: '#333' }}>{booking.owner_username}</span></Typography>
        <Typography variant="body2" color="text.secondary">Dates: <span style={{ fontWeight: 600, color: '#333' }}>{booking.start_date}</span> to <span style={{ fontWeight: 600, color: '#333' }}>{booking.end_date}</span></Typography>
        <Typography variant="body1" sx={{ fontWeight: 700, color: '#008080' }}>Total: ₱{booking.total_price || 'N/A'}</Typography>
        <Button 
          variant="contained" 
          sx={{
            mt: 1,
            borderRadius: 9999,
            bgcolor: '#008080',
            color: 'white',
            fontWeight: 600,
            alignSelf: 'flex-end',
            '&:hover': {
              bgcolor: '#006666',
              transform: 'scale(1.05)',
              boxShadow: '0 4px 10px rgba(0, 128, 128, 0.3)',
            },
            transition: 'all 0.3s ease-in-out',
          }}
        >
          View Details
        </Button>
      </Box>
    </Grid>
  );

  const activeBookings = getActiveBookings();
  const pastBookings = getPastBookings();
  const incomingBookings = getIncomingBookings();

  if (loading) {
    return (
      <Container maxWidth="lg">
        <Box sx={{ 
          display: 'flex', 
          justifyContent: 'center', 
          alignItems: 'center', 
          height: '60vh' 
        }}>
          <CircularProgress sx={{ color: '#008080' }} />
        </Box>
      </Container>
    );
  }

  const renderBookings = () => {
    let bookingsToRender = [];
    switch (activeTab) {
      case 0:
        bookingsToRender = activeBookings;
        break;
      case 1:
        bookingsToRender = pastBookings;
        break;
      case 2:
        bookingsToRender = incomingBookings;
        break;
      default:
        bookingsToRender = activeBookings;
    }

    if (bookingsToRender.length === 0) {
      return (
        <Box sx={{ textAlign: 'center', py: 6 }}>
          <Typography variant="h6" color="text.secondary">
            No bookings to display in this category.
          </Typography>
        </Box>
      );
    }

    return (
      <Grid container spacing={2} justifyContent="center">
        {bookingsToRender.map(renderBookingCard)}
      </Grid>
    );
  };

  return (
    <Container maxWidth="lg">
      <Box sx={{ mt: 4, mb: 4 }}>
        {alert.open && (
          <Alert 
            severity={alert.severity} 
            sx={{ 
              mb: 3, 
              borderRadius: '12px',
              '& .MuiAlert-icon': {
                color: alert.severity === 'success' ? '#2E7D32' : 
                       alert.severity === 'error' ? '#C62828' : 
                       alert.severity === 'warning' ? '#FF8F00' : '#008080'
              },
              '& .MuiAlert-message': {
                fontWeight: 500
              }
            }}
          >
            {alert.message}
          </Alert>
        )}

        <Typography 
          variant="h4" 
          sx={{ 
            fontWeight: 700, 
            color: '#008080',
            mb: 3,
            textAlign: 'center'
          }}
        >
          My Bookings
        </Typography>

        <Box sx={{ 
          backgroundColor: 'white', 
          borderRadius: '16px', 
          boxShadow: '0 4px 12px rgba(0, 128, 128, 0.1)',
          mb: 4
        }}>
          <Tabs 
            value={activeTab} 
            onChange={handleChangeTab} 
            centered 
            sx={{
              mb: 3,
              '.MuiTabs-indicator': {
                backgroundColor: '#008080',
              },
              '.MuiTab-root': {
                color: '#008080',
                fontWeight: 600,
                '&.Mui-selected': {
                  color: '#008080',
                },
              },
            }}
          >
            <Tab label="Active Bookings" />
            <Tab label="Past Bookings" />
            <Tab label="Incoming Bookings" />
          </Tabs>
          {renderBookings()}
        </Box>
      </Box>
    </Container>
  );
};

export default Bookings;
